t.t:
.cand-wrap { max-width: 680px; margin: 0 auto; }
.breadcrumb { font-size: 12.5px; color: var(--p-muted); margin-bottom: 20px; }
.breadcrumb a { color: var(--p-primary); text-decoration: none; }
.breadcrumb a:hover { text-decoration: underline; }

/* Banner da oportunidade seleccionada */
.ctx-banner {
    background: var(--p-primary-light);
    border-left: 4px solid var(--p-primary);
    border-radius: 0 10px 10px 0;
    padding: 14px 18px;
    margin-bottom: 24px;
    display: flex;
    align-items: center;
    gap: 14px;
    flex-wrap: wrap;
}
.ctx-banner .ctx-info strong { display: block; font-size: 14.5px; font-weight: 600; color: var(--p-primary); }
.ctx-banner .ctx-info span   { font-size: 12.5px; color: var(--p-muted); }
.ctx-banner-empty {
    background: #FFF8E6;
    border-left: 4px solid #BA7517;
    border-radius: 0 10px 10px 0;
    padding: 12px 18px;
    margin-bottom: 24px;
    font-size: 13.5px;
    color: #7A4F00;
}

/* Card do formulário */
.form-card {
    background: var(--p-card);
    border: 1px solid var(--p-border);
    border-radius: 14px;
    padding: 32px;
}
.form-card h2 {
    font-size: 21px;
    font-weight: 700;
    color: var(--p-primary);
    margin-bottom: 24px;
    padding-bottom: 16px;
    border-bottom: 1px solid var(--p-border);
}
.sec-label {
    font-size: 10.5px;
    text-transform: uppercase;
    letter-spacing: 0.1em;
    color: var(--p-muted);
    font-weight: 700;
    margin: 24px 0 14px;
    padding-bottom: 6px;
    border-bottom: 1px dashed var(--p-border);
}
.form-row { display: flex; gap: 16px; }
@media(max-width:560px) { .form-row { flex-direction: column; } }
.form-group { display: flex; flex-direction: column; gap: 5px; flex: 1; margin-bottom: 14px; }
.form-group label { font-size: 13px; font-weight: 500; color: var(--p-text); }
.form-group input,
.form-group select,
.form-group textarea {
    padding: 9px 12px;
    border: 1px solid var(--p-border);
    border-radius: 6px;
    font-size: 13.5px;
    font-family: inherit;
    color: var(--p-text);
    outline: none;
    transition: border .15s;
    background: #fff;
}
.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
    border-color: var(--p-primary);
    box-shadow: 0 0 0 3px rgba(15,76,129,0.08);
}
.form-group textarea { resize: vertical; min-height: 120px; }
.radio-group { display: flex; gap: 8px; flex-wrap: wrap; padding-top: 4px; }
.radio-opt {
    display: flex; align-items: center; gap: 6px;
    padding: 6px 14px;
    border: 1px solid var(--p-border);
    border-radius: 20px;
    cursor: pointer;
    font-size: 13px;
    transition: all .15s;
}
.radio-opt input { accent-color: var(--p-primary); }
.radio-opt:has(input:checked) {
    border-color: var(--p-primary);
    background: var(--p-primary-light);
    color: var(--p-primary);
    font-weight: 600;
}
.upload-zone {
    border: 1.5px dashed var(--p-border);
    border-radius: 8px;
    padding: 24px;
    text-align: center;
    cursor: pointer;
    transition: all .15s;
    background: #FAFBFD;
}
.upload-zone:hover { border-color: var(--p-primary); background: var(--p-primary-light); }
.upload-zone p   { font-size: 13.5px; font-weight: 500; color: var(--p-text); margin-bottom: 4px; }
.upload-zone small { font-size: 12px; color: var(--p-muted); }
.privacy-row {
    display: flex; gap: 10px;
    align-items: flex-start;
    margin-top: 10px;
}
.privacy-row input { accent-color: var(--p-primary); margin-top: 3px; flex-shrink: 0; }
.privacy-row label { font-size: 12.5px; color: var(--p-muted); line-height: 1.55; }
.form-actions {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-top: 28px;
    padding-top: 20px;
    border-top: 1px solid var(--p-border);
}
.link-back { font-size: 13px; color: var(--p-primary); text-decoration: none; font-weight: 500; }
.link-back:hover { text-decoration: underline; }
.char-counter { text-align: right; font-size: 11.5px; color: var(--p-muted); margin-top: 4px; }

/* Estado de sucesso */
.success-box {
    display: none;
    background: var(--p-action-light);
    border: 1px solid var(--p-action);
    border-radius: 12px;
    padding: 32px;
    text-align: center;
    margin-top: 24px;
}
.success-box .s-icon  { font-size: 40px; margin-bottom: 12px; }
.success-box h3 { font-size: 18px; color: var(--p-action-dark); margin-bottom: 8px; }
.success-box p  { font-size: 14px; color: var(--p-muted); margin-bottom: 20px; }

t.script:
function updateCounter() {
    const len = document.getElementById('f-motiv').value.length;
    document.getElementById('char-count').textContent = len + ' / 1000 caracteres';
}

async function submitCandidatura() {
    const btn = event.target;

    // Validações frontend
    const nome  = document.getElementById('f-nome').value.trim();
    const num   = document.getElementById('f-num').value.trim();
    const email = document.getElementById('f-email').value.trim();
    const curso = document.getElementById('f-curso').value;
    const ano   = document.querySelector('input[name="fano"]:checked')?.value;
    const motiv = document.getElementById('f-motiv').value.trim();
    const priv  = document.getElementById('f-privacy').checked;
    const tipo  = document.getElementById('f-tipo')?.value || 'estagio';

    if (!nome || !num || !email || !curso || !ano) {
        mostrarErro('Preenche todos os campos obrigatórios (*).');
        return;
    }
    if (!priv) {
        mostrarErro('Aceita a política de privacidade para continuar.');
        return;
    }

    btn.disabled = true;
    btn.textContent = 'A enviar...';

    try {
        // Lê o oportunidade_id do campo hidden injectado pelo QWeb
        const oppIdEl = document.getElementById('f-opp-id');
        const oppId   = oppIdEl ? parseInt(oppIdEl.value) || null : null;

        const res = await fetch('/crm_estudantil/submit_lead', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
                jsonrpc: '2.0', method: 'call', id: 1,
                params: {
                    name:             nome,
                    email:            email,
                    phone:            document.getElementById('f-phone').value.trim(),
                    student_number:   num,
                    course:           curso,
                    year:             ano,
                    opportunity_type: tipo,
                    motivation:       motiv,
                    oportunidade_id:  oppId,   // ← CORRECÇÃO: liga candidatura à oportunidade
                }
            })
        });
        const json = await res.json();
        if (json.result?.success) {
            document.getElementById('form-card').style.display = 'none';
            document.getElementById('success-box').style.display = 'block';
            window.scrollTo({ top: 0, behavior: 'smooth' });
        } else {
            mostrarErro(json.result?.message || 'Erro ao enviar.');
        }
    } catch {
        mostrarErro('Erro de ligação. Verifica a tua conexão e tenta novamente.');
    } finally {
        btn.disabled = false;
        btn.textContent = 'Enviar Candidatura';
    }
}

function mostrarErro(msg) {
    const el = document.getElementById('form-error');
    el.textContent = '⚠ ' + msg;
    el.style.display = 'block';
    el.scrollIntoView({ behavior: 'smooth', block: 'center' });
}

t.t:
.faq-header { margin-bottom: 28px; }
.faq-header h1 { font-size: 26px; font-weight: 700; color: var(--p-text); margin-bottom: 6px; }
.faq-header p  { font-size: 14.5px; color: var(--p-muted); }
.search-bar { position: relative; max-width: 560px; margin-bottom: 20px; }
.search-bar input {
    width: 100%; padding: 11px 14px 11px 40px;
    border: 1.5px solid var(--p-border); border-radius: 8px;
    font-size: 14px; font-family: inherit; outline: none; transition: border .15s;
}
.search-bar input:focus { border-color: var(--p-action); }
.search-bar .s-icon { position: absolute; left: 13px; top: 50%; transform: translateY(-50%); color: var(--p-muted); }
.cat-pills { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 28px; }
.cpill { padding: 5px 16px; border-radius: 20px; border: 1px solid var(--p-border);
    background: #fff; font-size: 13px; cursor: pointer; color: var(--p-muted); transition: all .15s; font-family: inherit; }
.cpill.active, .cpill:hover { background: var(--p-primary); color: #fff; border-color: var(--p-primary); }
.faq-item {
    background: var(--p-card); border: 1px solid var(--p-border);
    border-radius: 10px; margin-bottom: 10px; overflow: hidden; transition: box-shadow .15s;
}
.faq-item:hover { box-shadow: 0 2px 10px rgba(15,76,129,0.08); }
.faq-q {
    display: flex; align-items: center; gap: 12px;
    padding: 14px 18px; cursor: pointer; user-select: none;
}
.faq-q .q-text { flex: 1; font-size: 14px; font-weight: 600; color: var(--p-text); }
.faq-q .chevron { color: var(--p-primary); font-size: 18px; transition: transform .2s; flex-shrink: 0; }
.faq-item.open .chevron { transform: rotate(180deg); }
.faq-a {
    display: none; padding: 0 18px 16px;
    font-size: 13.5px; color: var(--p-muted); line-height: 1.65;
    border-top: 1px solid var(--p-border); padding-top: 12px;
}
.faq-item.open .faq-a { display: block; }
.cta-box {
    border: 2px dashed var(--p-action); border-radius: 12px;
    padding: 32px; text-align: center; margin-top: 36px;
}
.cta-box h3 { font-size: 16px; font-weight: 700; color: var(--p-text); margin-bottom: 8px; }
.cta-box p  { font-size: 14px; color: var(--p-muted); margin-bottom: 18px; }

t.script:
let activeCat = 'todos';
function toggleFaq(el) { el.closest('.faq-item').classList.toggle('open'); }
function setFaqCat(el) {
    document.querySelectorAll('.cpill').forEach(p => p.classList.remove('active'));
    el.classList.add('active');
    activeCat = el.dataset.cat;
    filterFaq();
}
function filterFaq() {
    const q = document.getElementById('faq-search').value.toLowerCase();
    document.querySelectorAll('.faq-item').forEach(item => {
        const catMatch = activeCat === 'todos' || item.dataset.cat === activeCat;
        const textMatch = !q || item.innerText.toLowerCase().includes(q);
        item.style.display = (catMatch && textMatch) ? '' : 'none';
    });
}
